// Copyright 2025, NoFeeSwap LLC - All rights reserved.
pragma solidity ^0.8.28;

import {MulDivOverflow} from "./Errors.sol";

/// @title Contains 512-bit multiplication and division functions
/// Credit to Remco Bloemen under MIT license https://xn--2-umb.com/21/muldiv
/// for several functions in this library.
library FullMathLibrary {
  ///                           _____   _____   _____
  /// @notice 512-bit addition 'r1 r0 = a1 a0 + b1 b0'.
  /// Overflow should be avoided externally.
  /// @param a0 Least significant 256 bits of the first number.
  /// @param a1 Most significant 256 bits of the first number.
  /// @param b0 Least significant 256 bits of the second number.
  /// @param b1 Most significant 256 bits of the second number.
  /// @return r0 Least significant 256 bits of the addition.
  /// @return r1 Most significant 256 bits of the addition.
  function add512(
    uint256 a0,
    uint256 a1,
    uint256 b0,
    uint256 b1
  ) internal pure returns (
    uint256 r0,
    uint256 r1
  ) {
    //      s0
    //      a1 a0
    // +    b1 b0
    // -----------
    //      r1 r0
    //
    // where 's0 := lt(r0, a0)'.
    assembly {
      r0 := add(a0, b0)
      r1 := add(
        add(a1, b1),
        // 'r0 < a0' indicates that the addition 'a0 + b0' has overflowed. In
        // this case '1' needs to be added to the most significant 256 bits of
        // the output.
        lt(r0, a0)
      )
    }
  }

  ///                              _____   _____   _____
  /// @notice 512-bit subtraction 'r1 r0 = a1 a0 - b1 b0'.
  /// Underflow should be avoided externally.
  /// @param a0 Least significant 256 bits of the minuend.
  /// @param a1 Most significant 256 bits of the minuend.
  /// @param b0 Least significant 256 bits of the subtrahend.
  /// @param b1 Most significant 256 bits of the subtrahend.
  /// @return r0 Least significant 256 bits of the subtraction.
  /// @return r1 Most significant 256 bits of the subtraction.
  function sub512(
    uint256 a0,
    uint256 a1,
    uint256 b0,
    uint256 b1
  ) internal pure returns (
    uint256 r0,
    uint256 r1
  ) {
    //      a1 a0
    // -    b1 b0
    // -----------
    //      s1 r0
    // -    s0
    // -----------
    //      r1 r0
    //
    // where 's0 := lt(a0, b0)' and 's1 := (a1 - b1) % (2 ** 256)'.
    assembly {
      r0 := sub(a0, b0)
      r1 := sub(
        sub(a1, b1),
        // 'a0 < b0' indicates that the subtraction 'a0 - b0' has underflowed.
        // In this case '1' needs to be subtracted from the most significant
        // 256 bits of the output.
        lt(a0, b0)
      )
    }
  }

  ///                           ___________
  /// @notice 512-bit multiply 'prod1 prod0 = a * b'.
  /// @param a The multiplicand.
  /// @param b The multiplier.
  /// @return prod0 Least significant 256 bits of the product.
  /// @return prod1 Most significant 256 bits of the product.
  function mul512(
    uint256 a,
    uint256 b
  ) internal pure returns (
    uint256 prod0, 
    uint256 prod1
  ) {
    assembly {
      // 'mm := a * b - (2 ** 256 - 1) * q'
      let mm := mulmod(a, b, not(0))

      // 'prod0 := a * b - (2 ** 256) * p'
      prod0 := mul(a, b)

      prod1 := sub(
        // 'mm - prod0 == q'.
        sub(mm, prod0),
        //               a * b                 a * b
        // p == floor(----------) <= floor(--------------) == q
        //             2 ** 256             2 ** 256 - 1
        //
        // On the other hand, since
        //
        //      a * b          a * b                  a * b
        // -------------- - ---------- == ----------------------------- < 1
        //  2 ** 256 - 1     2 ** 256      (2 ** 256) * (2 ** 256 - 1)
        //
        // we have 'q - p <= 1'.
        //
        // Hence, either 'p == q' or 'p == q - 1'.
        //
        // If 'p == q', then 'mm - prod0 == q >= 0'.
        // If 'p == q - 1', then 'prod0 - mm == (2 ** 256) - q > 0'.
        //
        // Since 'p == q' and 'p == q - 1' are mutually exclusive, we can argue
        // that:
        //
        // 'p == q' if and only if 'mm >= prod0'.
        // 'p == q - 1' if and only if 'mm < prod0'.
        //
        // Hence, in the latter case, we should subtract by '1'.
        lt(mm, prod0)
      )
    }
  }

  /// @notice Calculates (a * b) / denominator when 
  /// 'a * b < denominator * (denominator - 1)'.
  /// @param a The multiplicand.
  /// @param b The multiplier.
  /// @param denominator The divisor.
  /// @return result '(a * b) / denominator'.
  function cheapMulDiv(
    uint256 a,
    uint256 b,
    uint256 denominator
  ) internal pure returns (
    uint256 result
  ) {
    assembly {
      result := sub(denominator, 1)

      // 's := a * b - q * (denominator - 1)'
      // 'r := a * b - p * denominator'
      // 's - r == p * denominator == p' [mod (denominator - 1)]
      result := addmod(
        mulmod(a, b, result),
        // This subtraction is safe because 
        // '(a * b) % denominator <= denominator - 1'.
        sub(result, mulmod(a, b, denominator)),
        result
      )
      // Notice that 'result <= denominator - 1' and because of the input
      // requirement, we have 'p = (a * b) / denominator <= denominator - 1'.
      // Hence, 'result == s - r == p'.
    }
  }

  /// @notice Calculates the modular inverse of an odd number modulo '2 ** 256'
  /// Input should be odd.
  /// @param value The number whose modular inverse to be calculated.
  /// @return inverse A 256-bit inverse satisfying
  /// 'value * inverse == 1' [mod 2 ** 256].
  function modularInverse(
    uint256 value
  ) internal pure returns (
    uint256 inverse
  ) {
    unchecked {
      // Compute the inverse by starting with a seed that is correct for four
      // bits. That is, 'value * inverse = 1' [mod 2 ** 4].
      inverse = 3 * value ^ 2;
      // Now use Newton-Raphson iterations to improve the precision. Thanks to
      // Hensel's lifting lemma, this also works in modular arithmetic,
      // doubling the correct bits in each step.
      inverse *= 2 - value * inverse;
      inverse *= 2 - value * inverse;
      inverse *= 2 - value * inverse;
      inverse *= 2 - value * inverse;
      inverse *= 2 - value * inverse;
      inverse *= 2 - value * inverse;
    }
  }

  ///                          ________
  /// @notice 768-bit multiply q2 q1 q0 = a * b * c
  /// @param a The multiplicand.
  /// @param b The first multiplier.
  /// @param c The second multiplier.
  /// @return q0 Least significant 256 bits of the product.
  /// @return q1 Middle 256 bits of the product.
  /// @return q2 Most significant 256 bits of the product.
  function mul768(
    uint256 a,
    uint256 b,
    uint256 c
  ) internal pure returns (
    uint256 q0,
    uint256 q1,
    uint256 q2
  ) {
    //          a
    // x        b
    // -----------
    //      q1 q0
    // x        c
    // -----------
    //   ss 
    //      mm q0
    // + q2 q1  0
    // -----------
    //   q2 q1 q0
    //
    uint256 mm;
    (q0, q1) = mul512(a, b);
    (q1, q2) = mul512(q1, c);
    (q0, mm) = mul512(q0, c);
    assembly {
      q1 := add(q1, mm)
      // 'q1 < mm' indicates that the above addition has overflowed (i.e.,
      // 'ss == 1') and hence, '1' needs to be added to the most significant
      // 256 bits of the product.
      q2 := add(q2, lt(q1, mm))
    }
  }

  /// @notice Calculates 
  ///
  ///         a * b * c
  /// 'min(----------------, 2 ** 216 - 1)'
  ///       d * (2 ** 143)
  ///
  /// with full precision when 'a * b * c != 0'.
  /// @param a The multiplicand.
  /// @param b The first multiplier.
  /// @param c The second multiplier.
  /// @param d The denominator.
  /// @param roundUp Whether to round up the result.
  /// @return result The output value '(a * b * c) / (d * (2 ** 143))' which is
  /// capped by '2 ** 216 - 1'.
  function mulDiv(
    uint256 a,
    uint256 b,
    uint256 c,
    uint256 d,
    bool roundUp
  ) internal pure returns (
    uint256 result
  ) {
    unchecked {
      // ________
      // q2 q1 q0 = a * b * c
      (uint256 q0, uint256 q1, uint256 q2) = mul768(a, b, c);

      // If 'q2 >= (1 << 103)', then the output is greater than or equal to
      //
      //  (2 ** 103) * (2 ** 256) * (2 ** 256)
      // -------------------------------------- == 2 ** 216
      //        (2 ** 256) * (2 ** 143)
      //
      // In this case, '2 ** 216 - 1' should be returned.
      if (q2 >= (1 << 103)) return ((1 << 216) - 1);

      // Divide the numerator by '2 ** 143'
      (q2, q1) = (
        (q2 << 113) | (q1 >> 143),
        (q1 << 113) | (q0 >> 143)
      );

      // Calculating the remainder of the numerator modulo 'd'.
      uint256 r;
      assembly {
        r := addmod(
          addmod(q1, q2, d), // (q1 + q2) % d
          mulmod(q2, not(0), d), // (q2 * (2 ** 256 - 1)) % d
          d
        ) // (q1 + q2 * (2 ** 256)) % d
      }

      //                         _____
      // 'r' is subtracted from 'q2 q1'.
      assembly {
        // 'q1 < r' indicates that the subtraction 'q1 - r' underflows.
        // In this case '1' needs to be subtracted from q2.
        q2 := sub(q2, lt(q1, r))
        q1 := sub(q1, r)
      }

      // Determines whether to return '2 ** 216 - 1'.
      //                _____
      // Check whether 'q2 q1 >= (2 ** 256) * d'.
      if (q2 >= d) return ((1 << 216) - 1);

      // 'd' is factored into an odd part and a power of two. 
      // Then, the numerator is divided by the power of two.
      {
        // This is the largest power of two that 'd' is divisible by.
        uint256 twos = (0 - d) & d;
        assembly {
          // Dividing 'd' by 'twos'.
          d := div(d, twos)

          //           _____
          // Dividing 'q2 q1' by 'twos' and storing the least significant '256'
          // bits in 'q1'.
          q1 := or(
            div(q1, twos), // 'q1 / (2 ** k)'
            mul(
              q2,
              add(
                div(
                  sub(0, twos), // '2 ** 256 - 2 ** k'
                  twos // '2 ** k'
                ), // '2 ** (256 - k) - 1'
                1
              ) // '(2 ** (256 - k)) % (2 ** 256)'
            ) // '(q2 * (2 ** (256 - k))) % (2 ** 256)'
          ) // '(q2 * (2 ** (256 - k)) + q1 / (2 ** k)) % (2 ** 256)'
        }
      }

      // The result can now be calculated precisely using modular inverse.
      // Let 'di := modularInverse(d)'.
      //
      //  _____
      // 'q2 q1 == d * result'
      // '(2 ** 256) * q2 + q1 == d * result'
      // 'di * (2 ** 256) * q2 + di * q1 == di * d * result'
      // 'di * (2 ** 256) * q2 + di * q1 == ((2 ** 256) * k + 1) * result'
      // 'di * q1 == result' [mod 2 ** 256]
      result = modularInverse(d) * q1;

      // If either of the remainders are positive, then the result should be
      // rounded up.
      if (roundUp) {
        if ((q0 & 0x7FFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFF) > 0 || r > 0) {
          ++result;
        }
      }

      // Determines whether to return '2 ** 216 - 1'.
      if (result >= (1 << 216)) return ((1 << 216) - 1);
    }
  }

  /// @notice Calculates
  ///
  ///      a * b * c
  /// '----------------'
  ///   d * (2 ** 111)
  ///
  /// with full precision. Overflows if the result exceeds 'type(int256).max'.
  /// 'e' must be the modular inverse of 'd / (2 ** k)' where 'k' is the
  /// largest power of two within 'd'.
  /// We should have 'a * b * c != 0' and 'd != 0'.
  /// @param a The multiplicand.
  /// @param b The first multiplier.
  /// @param c The second multiplier.
  /// @param d The denominator.
  /// @param e Modular inverse of the odd part of the denominator.
  /// @param roundUp Whether to round up the result.
  /// @return result The output value '(a * b * c) / (d * (2 ** 111))' if there
  /// is no overflow.
  /// @return overflow Whether the result overflows.
  function mulDiv(
    uint256 a,
    uint256 b,
    uint256 c,
    uint256 d,
    uint256 e,
    bool roundUp
  ) internal pure returns (
    uint256 result,
    bool overflow
  ) {
    unchecked {
      // ________
      // q2 q1 q0 = a * b * c
      (uint256 q0, uint256 q1, uint256 q2) = mul768(a, b, c);

      // If 'q2 >= (1 << 111)', then the output is greater than or equal to
      //
      //  (2 ** 111) * (2 ** 256) * (2 ** 256)
      // -------------------------------------- == 2 ** 256
      //        (2 ** 256) * (2 ** 111)
      //
      // In this case, we return overflow.
      if (q2 >= (1 << 111)) return (0, true);

      // Divide the numerator by '2 ** 111'
      (q2, q1) = (
        (q2 << 145) | (q1 >> 111),
        (q1 << 145) | (q0 >> 111)
      );

      // Calculating the remainder of the numerator modulo 'd'.
      uint256 r;
      assembly {
        r := addmod(
          addmod(q1, q2, d), // (q1 + q2) % d
          mulmod(q2, not(0), d), // (q2 * (2 ** 256 - 1)) % d
          d
        ) // (q1 + q2 * (2 ** 256)) % d
      }

      //                         _____
      // 'r' is subtracted from 'q2 q1'.
      assembly {
        // 'q1 < r' indicates that the subtraction 'q1 - r' underflowes.
        // In this case '1' needs to be subtracted from q2.
        q2 := sub(q2, lt(q1, r))
        q1 := sub(q1, r)
      }

      // Determines whether to return overflow.
      // The following equality is satisfied if and only if
      //
      //      a * b * c
      // '---------------- >= (2 ** 256)'
      //   d * (2 ** 111)
      //
      if (q2 >= d) return (0, true);

      // 'd' is factored into an odd part and a power of two and the numerator
      // is divided by the power of two.
      d = (0 - d) & d;
      assembly {
        q1 := or(
          div(q1, d), // q1 / (2 ** k)
          mul(
            q2,
            add(
              div(
                sub(0, d), // '2 ** 256 - 2 ** k'
                d // '2 ** k'
              ), // '2 ** (256 - k) - 1'
              1
            ) // '(2 ** (256 - k)) % (2 ** 256)'
          ) // '(q2 * (2 ** (256 - k))) % (2 ** 256)'
        ) // '(q2 * (2 ** (256 - k)) + q1 / (2 ** k)) % (2 ** 256)'
      }

      // The result can now be calculated precisely using 'e'.
      //  _____
      // 'q2 q1 == d * result'
      // '(2 ** 256) * q2 + q1 == d * result'
      // 'e * (2 ** 256) * q2 + e * q1 == e * d * result'
      // 'e * (2 ** 256) * q2 + e * q1 == ((2 ** 256) * k + 1) * result'
      // 'e * q1 == result' [mod 2 ** 256]
      result = e * q1;

      // If either of the remainders are positive, then the result should be
      // rounded up.
      if (roundUp) {
        if ((q0 & 0x7FFFFFFFFFFFFFFFFFFFFFFFFFFF) > 0 || r > 0) {
          ++result;
        }
      }

      // Determines whether to overflow.
      if (result >= (1 << 255)) return (0, true);
    }
  }

  /// @notice Calculates floor((a * b) / denominator) with full precision.
  /// Overflow should be avoided externally.
  /// @param a The multiplicand
  /// @param b The multiplier
  /// @param denominator The divisor
  /// @return result The 256-bit result
  function mulDiv(
    uint256 a,
    uint256 b,
    uint256 denominator
  ) internal pure returns (
    uint256 result
  ) {
    unchecked {
      //                   ___________
      // 512-bit multiply 'prod1 prod0 = a * b'
      // Compute the product mod 2**256 and mod 2 ** 256 - 1
      // then use the Chinese Remainder Theorem to reconstruct
      // the 512 bit result. The result is stored in two 256
      // variables such that product = prod1 * (2 ** 256) + prod0
      (uint256 prod0, uint256 prod1) = mul512(a, b);

      // Short circuit 256 by 256 division
      // This saves gas when a * b is small, at the cost of making the
      // large case a bit more expensive. Depending on your use case you
      // may want to remove this short circuit and always go through the
      // 512 bit path.
      if (prod1 == 0) {
        assembly {
          result := div(prod0, denominator)
        }
        return result;
      }

      ///////////////////////////////////////////////
      // 512 by 256 division.
      ///////////////////////////////////////////////

      //                                                        ___________
      // Make division exact by subtracting the remainder from 'prod1 prod0'
      // Compute remainder using mulmod
      // Note mulmod(_, _, 0) == 0
      uint256 remainder;
      assembly {
        remainder := mulmod(a, b, denominator)
      }

      // Subtract 256 bit number from 512 bit number
      assembly {
        prod1 := sub(prod1, gt(remainder, prod0))
        prod0 := sub(prod0, remainder)
      }

      // Factor powers of two out of denominator
      // Compute largest power of two-divisor of denominator.
      // Always >= 1 unless the denominator is zero, then twos is zero.
      uint256 twos = (0 - denominator) & denominator;
      // Divide denominator by power of two
      assembly {
        denominator := div(denominator, twos)
      }

      //         ___________
      // Divide 'prod1 prod0' by the factors of two
      assembly {
        prod0 := div(prod0, twos)
      }
      // Shift in bits from prod1 into prod0. For this we need
      // to flip `twos` such that it is 2**256 / twos.
      // If twos is zero, then it becomes one
      assembly {
        twos := add(div(sub(0, twos), twos), 1)
      }
      prod0 |= prod1 * twos;

      // Invert denominator mod 2**256
      // Now that denominator is an odd number, it has an inverse
      // modulo 2**256 such that denominator * inv = 1 mod 2**256.
      // Compute the inverse by starting with a seed that is correct
      // correct for four bits. That is, denominator * inv = 1 mod 2**4
      // If denominator is zero the inverse starts with 2
      // Now use Newton-Raphson iteration to improve the precision.
      // Thanks to Hensel's lifting lemma, this also works in modular
      // arithmetic, doubling the correct bits in each step.
      uint256 inv = modularInverse(denominator);
      // If denominator is zero, inv is now 128

      // Because the division is now exact we can divide by multiplying
      // with the modular inverse of the denominator. This will give us the
      // correct result modulo 2**256. Since the preconditions guarantee
      // that the outcome is less than 2**256, this is the final result.
      // We don't need to compute the high bits of the result and prod1
      // is no longer required.
      result = prod0 * inv;
      return result;
    }
  }

  /// @notice Calculates ceiling((a * b) / denominator) with full precision.
  /// Overflow should be avoided externally.
  /// @param a The multiplicand
  /// @param b The multiplier
  /// @param denominator The divisor
  /// @return result The 256-bit result
  function mulDivRoundUp(
    uint256 a,
    uint256 b,
    uint256 denominator
  ) internal pure returns (uint256 result) {
    result = mulDiv(a, b, denominator);
    // The result is incremented if 'a * b' is not divisible by 'denominator'.
    assembly {
      result := add(result, gt(mulmod(a, b, denominator), 0))
    }
  }

  /// @notice Calculates floor((a * b) / denominator) with full precision.
  /// Throws in case of overflow.
  /// @param a The multiplicand
  /// @param b The multiplier
  /// @param denominator The divisor
  /// @return result The 256-bit result
  function safeMulDiv(
    uint256 a,
    uint256 b,
    uint256 denominator
  ) internal pure returns (uint256 result) {
    (, uint256 prod1) = mul512(a, b);
    require(prod1 < denominator, MulDivOverflow(a, b, denominator));
    result = mulDiv(a, b, denominator);
  }

  /// @notice Calculates ceiling((a * b) / denominator) with full precision.
  /// Throws in case of overflow.
  /// @param a The multiplicand
  /// @param b The multiplier
  /// @param denominator The divisor
  /// @return result The 256-bit result
  function safeMulDivRoundUp(
    uint256 a,
    uint256 b,
    uint256 denominator
  ) internal pure returns (uint256 result) {
    // The result is incremented if 'a * b' is not divisible by 'denominator'.
    assembly {
      result := gt(mulmod(a, b, denominator), 0)
    }
    result += safeMulDiv(a, b, denominator);
  }
}

contracts/utilities/Errors.sol.content:
// Copyright 2025, NoFeeSwap LLC - All rights reserved.
pragma solidity ^0.8.28;

import {Index} from "./Index.sol";
import {X15} from "./X15.sol";
import {X47} from "./X47.sol";
import {X59} from "./X59.sol";
import {X111} from "./X111.sol";
import {X127} from "./X127.sol";
import {X208} from "./X208.sol";
import {X216} from "./X216.sol";
import {Tag} from "./Tag.sol";

/// @notice Thrown in case of overflow when attempting to calculate
/// '(a * b) / denominator'.
error MulDivOverflow(uint256 a, uint256 b, uint256 denominator);

/// @notice Thrown in case of overflow or underflow when attempting to
/// calculate 'a + b'.
error SafeAddFailed(X127 a, X127 b);

/// @notice Thrown when balance exceeds 'type(uint128).max'.
error BalanceOverflow(uint256 balance);

/// @notice Thrown when safe cast into an int256 overflows.
error SafeCastOverflow(uint256 value);

/// @notice Thrown when the given 'qSpacing' is less than 'minLogSpacing'.
error LogSpacingIsTooSmall(X59 qSpacing);

/// @notice Thrown when attempting to initialize a curve sequence on blank
/// intervals.
error BlankIntervalsShouldBeAvoided(X59 qLower, X59 qUpper);

/// @notice Thrown when 'curveLength' is zero upon initialization.
error CurveLengthIsZero();

/// @notice Each member of the curve sequence should be in-between the
/// preceding two members. Thrown when a given initial curve sequence violates
/// this rule.
error InvalidCurveArrangement(X59 q0, X59 q1, X59 q2);

/// @notice Thrown when 'curveLength' is out of range.
error CurveIndexOutOfRange(Index length);

/// @notice Thrown in case of overflow when attempting to calculate 
///
/// 'amount := ceiling(
///
///     shares *
///
///     (getZeroForOne() ? sqrtOffset : sqrtInverseOffset) * 
///
///      multiplier
///     ------------
///       2 ** 208
///  )'.
error SafeOutOfRangeAmountOverflow(
  X127 sqrtOffsetOrSqrtInverseOffset,
  X208 growthMultiplier,
  int256 shares
);

/// @notice Thrown in case of overflow when attempting to calculate 
///
/// 'amount := ceiling(
///
///     (zeroOrOne ? sqrtOffset : sqrtInverseOffset) * 
///
///      liquidity      integral
///     ----------- * -------------
///       2 ** 111     outgoingMax
///  )'.
error SafeInRangeAmountOverflow(
  X127 sqrtOffsetOrSqrtInverseOffset,
  X216 integral,
  X111 liquidity,
  X216 outgoingMax,
  uint256 outgoingMaxModularInverse
);

/// @notice Thrown when the second horizontal coordinate of a given kernel is
/// '0'. In this case, we have a vertical jump at the origin which limits
/// liquidity growth.
error SecondHorizontalCoordinateIsZero();

/// @notice The horizontal coordinates should be monotonically non-decreasing.
error NonMonotonicHorizontalCoordinates(X59 q_i, X59 q_j);

/// @notice The vertical coordinates should be monotonically non-decreasing.
error NonMonotonicVerticalCoordinates(X15 c_i, X15 c_j);

/// @notice There should not be repetitive points.
error RepetitiveKernelPoints(X15 c_i, X59 q_i);

/// @notice Thrown when the horizontal coordinates of a non-vertical and 
/// non-horizontal segment are closer than '2 ** 32'.
error SlopeTooHigh(X59 q_i, X59 q_j);

/// @notice Thrown when the horizontal coordinates of a given 'kernelCompact'
/// exceeds 'qSpacing'.
error HorizontalCoordinatesMayNotExceedLogSpacing(X59 q_j, X59 qSpacing);

/// @notice There should not be three repetitive horizontal coordinates. A 
/// vertical jump (i.e., discontinuity) is permitted and can be constructed
/// via two repetitive horizontal coordinates. However, three repetitive
/// horizontal coordinates are always redundant and should be avoided.
error RepetitiveHorizontalCoordinates(X59 q_i);

/// @notice There should not be three repetitive vertical coordinates. A 
/// horizontal segment (i.e., constant range) is permitted and can be 
/// constructed via two repetitive vertical coordinates. However, three
/// repetitive vertical coordinates are always redundant and should be
/// avoided.
error RepetitiveVerticalCoordinates(X15 c_i);

/// @notice Thrown when 'kernelLength' is out of range.
error KernelIndexOutOfRange(Index length);

/// @notice The last vertical coordinate should be equal to 'oneX15'.
error LastVerticalCoordinateMismatch(X15 c_j);

/// @notice Thrown when growth exceeds maximum permitted value of 'maxGrowth'.
error GrowthOverflow();

/// @notice Thrown when accrued growth portion values exceed '2 ** 104 - 1'.
error AccruedGrowthPortionOverflow(X127 accruedValue);

/// @notice Thrown when given flags are invalid or not consistent with hook.
error InvalidFlags(uint256);

/// @notice Thrown when the numerical search for outgoing target fails which 
/// should never heappen.
error SearchingForOutgoingTargetFailed();

/// @notice Thrown when the numerical search for incoming target fails which
/// should never heappen.
error SearchingForIncomingTargetFailed();

/// @notice Thrown when the numerical search for overshoot fails which should
/// never heappen.
error SearchingForOvershootFailed();

/// @notice Thrown if attempting to unlock the protocol while already unlocked.
error AlreadyUnlocked(address currentCaller);

/// @notice Thrown when any of the following methods are invoked prior to the
/// protocol being unlocked:
///
///   'INofeeswap.clear'
///   'INofeeswap.take'
///   'INofeeswap.settle'
///   'INofeeswap.transferTransientBalanceFrom'
///   'INofeeswap.modifyBalance'
///   'INofeeswap.swap'
///   'INofeeswapDelegatee.modifyPosition'
///   'INofeeswapDelegatee.donate'
///
error ProtocolIsLocked();

/// @notice Thrown when attempting to perform the following operations on a 
/// pool which is locked:
///
///   'INofeeswap.swap'
///   'INofeeswapDelegatee.modifyPosition'
///   'INofeeswapDelegatee.donate'
///   'INofeeswapDelegatee.modifyKernel'
///   'INofeeswapDelegatee.modifyPoolGrowthPortion'
///   'INofeeswapDelegatee.updateGrowthPortions'
///   'INofeeswapDelegatee.collectPool'
///   'INofeeswapDelegatee.collectProtocol'
///
error PoolIsLocked(uint256 poolId);

/// @notice Thrown when the deployment of static parameters fail.
error DeploymentFailed();

/// @notice Thrown when the method 'redeployStaticParamsAndKernel' is run
/// externally.
error CannotRedeployStaticParamsAndKernelExternally();

/// @notice Thrown when attempting to sync protocol's reserve of native token.
error NativeTokenCannotBeSynced();

/// @notice Thrown when the spender allowance for a tag is insufficient.
error InsufficientPermission(address spender, Tag tag);

/// @notice Thrown when the total number of shares accross all liquidity
/// intervals exceed '2 ** 127 - 1'.
error SharesGrossOverflow(int256 sharesGross);

/// @notice Thrown when attempting to access a pool which does not exist.
error PoolDoesNotExist(uint256 poolId);

/// @notice Thrown when the owner balance for a tag is insufficient.
error InsufficientBalance(address owner, Tag tag);

/// @notice Throws when Sentinel response is invalid.
error InvalidSentinelResponse(bytes4 response);

/// @notice Thrown when the given 'zeroForOne' is not in agreement with 
/// 'logPriceLimitOffsetted'.
error InvalidDirection(X59 current, X59 limit);

/// @notice Thrown when attempting to initialize a pool that already exists.
error PoolExists(uint256 poolId);

/// @notice Thrown when 'log(pOffset)' is not within the range '[-89, +89]'.
error LogOffsetOutOfRange(X59 qOffset);

/// @notice Thrown when the given tags are not in the correct order, i.e.,
/// 'tag0 < tag1'.
error TagsOutOfOrder(Tag tag0, Tag tag1);

/// @notice Thrown when a given growth portion is greater than one.
error InvalidGrowthPortion(X47 poolGrowthPortion);

/// @notice Thrown when a given logarithmic price does not belong to the range
/// '[log(pOffset) - 16 + 1 / (2 ** 59), log(pOffset) + 16 - 1 / (2 ** 59)]'.
error LogPriceOutOfRange(X59 logPrice);

/// @notice Thrown when attempting to mint/burn a position with zero shares or
/// when the number of shares does not belong to 
/// '[- type(int128).max, type(int128).max]'.
error InvalidNumberOfShares(int256 shares);

/// @notice Thrown when attempting to initialize a pool with 'poolId == 0'.
error PoolIdCannotBeZero();

/// @notice Thrown when attempting to access protocol operations via an
/// unauthorized address.
error OnlyByProtocol(address attemptingAddress, address protocolAddress);

/// @notice Thrown when attempting to access pool operations via an
/// unauthorized address.
error OnlyByPoolOwner(address attemptingAddress, address poolOwnerAddress);

/// @notice Thrown when attempting to mint/burn a position with invalid
/// lower bound which is not equal to interval boundaries modulo 'qSpacing'.
error LogPriceMinIsNotSpaced(X59 logPriceMin);

/// @notice Thrown when attempting to mint/burn a position with invalid
/// upper bound which is not equal to interval boundaries modulo 'qSpacing'.
error LogPriceMaxIsNotSpaced(X59 logPriceMax);

/// @notice Thrown when attempting to mint/burn a position with invalid
/// lower bound which is not greater than 'qSpacing'
error LogPriceMinIsInBlankArea(X59 logPriceMin);

/// @notice Thrown when attempting to mint/burn a position with invalid
/// lower bound which is not less than 'thirtyTwoX59 - qSpacing'.
error LogPriceMaxIsInBlankArea(X59 logPriceMax);

/// @notice Thrown when the given logPrices for a position are not in the
/// correct order.
error LogPricesOutOfOrder(X59 logPriceMin, X59 logPriceMax);

/// @notice Thrown when attempting donate to a pool whose donate flag is not 
/// active.
error DonateIsNotAllowed(uint256 poolId);

/// @notice Thrown when attempting to perform a donate to an empty interval.
error CannotDonateToEmptyInterval();

/// @notice Thrown when attempting to change an immutable kernel.
error ImmutableKernel(uint256 poolId);

/// @notice Thrown when attempting to change an immutable poolGrowthPortion.
error ImmutablePoolGrowthPortion(uint256 poolId);

/// @notice Thrown when attempting to make a delegate call to the protocol.
error NoDelegateCall(address context);

/// @notice Thrown when transient balances are not cleared.
error OutstandingAmount();

/// @notice Thrown when attempting to transfer NofeeAssets to address 0.
error CannotTransferToAddressZero();

/// @notice Thrown when the amount to be cleared is not equal to the transient
/// balance of 'msg.sender'.
error NotEqualToTransientBalance(int256 currentBalance);

/// @notice Thrown when the size of 'hookData' exceeds 'type(uint16).max'.
error HookDataTooLong(uint256 hookDataByteCount);

/// @notice Thrown when attempting to transfer ownership to address 0.
error AdminCannotBeAddressZero();

/// @notice Thrown when attempting to settle a tag with nonzero 'msg.value'.
error MsgValueIsNonZero(uint256 msgValue);

/// @notice Thrown when attempting to mint a position after burning it in the
/// same transaction.
error CannotMintAfterBurning(uint256 poolId, X59 qMin, X59 qMax);

contracts/utilities/Tag.sol.content:
// Copyright 2025, NoFeeSwap LLC - All rights reserved.
pragma solidity ^0.8.28;

import {X59} from "./X59.sol";

// Type 'Tag' may refer to any of the followings:
//
// - Native token corresponding to 'Tag.wrap(0)'.
//
// - An ERC-20 address, i.e., 'Tag.wrap(uint256(uint160(tokenAddress)))'.
//
// - An ERC-1155 token whose value is determined by hashing token address and
// token ID, i.e., 
// 'Tag.wrap(uint256(keccak256(abi.encodePacked(tokenAddress, tokenId))))'.
//
// - An ERC-6909 token whose value is determined by hashing token address and
// token ID, i.e., 
// 'Tag.wrap(uint256(keccak256(abi.encodePacked(tokenAddress, tokenId))))'.
//
// - A nofeeswap position whose value is determined by hashing, poolId and
// min/max position boundaries, i.e., 
// 'Tag.wrap(uint256(keccak256(abi.encodePacked(
//    poolId,
//    qMin,
//    qMax
//  ))))'.
//
type Tag is uint256;

Tag constant native = Tag.wrap(0);

using {equals as ==, notEqual as !=} for Tag global;
using {lessThan as <, greaterThan as >} for Tag global;
using {
  lessThanOrEqualTo as <=,
  greaterThanOrEqualTo as >=
} for Tag global;

function equals(
  Tag value0,
  Tag value1
) pure returns (
  bool result
) {
  assembly {
    result := eq(value0, value1)
  }
}

function notEqual(
  Tag value0,
  Tag value1
) pure returns (
  bool result
) {
  return !(value0 == value1);
}

function lessThan(
  Tag value0,
  Tag value1
) pure returns (
  bool result
) {
  assembly {
    result := lt(value0, value1)
  }
}

function greaterThan(
  Tag value0,
  Tag value1
) pure returns (
  bool result
) {
  assembly {
    result := gt(value0, value1)
  }
}

function lessThanOrEqualTo(
  Tag value0,
  Tag value1
) pure returns (
  bool result
) {
  return !(value0 > value1);
}

function greaterThanOrEqualTo(
  Tag value0,
  Tag value1
) pure returns (
  bool result
) {
  return !(value0 < value1);
}

library TagLibrary {
  /// @notice Generates a tag given an ERC-20 address.
  /// @param tokenAddress The given ERC-20 address to be transformed to the
  /// type 'tag'.
  function tag(
    address tokenAddress
  ) internal pure returns (
    Tag tokenTag
  ) {
    assembly {
      tokenTag := and(tokenAddress, sub(shl(160, 1), 1))
    }
  }

  /// @notice Generates a tag given a multi-token address and tokenId.
  /// @param tokenAddress The given multi-token address to be transformed to
  /// the type 'tag'.
  /// @param tokenId The given multi-token id to be used to generate 'tag'.
  function tag(
    address tokenAddress,
    uint256 tokenId
  ) internal pure returns (
    Tag tokenTag
  ) {
    assembly {
      mstore(20, tokenAddress)
      mstore(0, tokenId)
      tokenTag := keccak256(0, 52)
    }
  }

  /// @notice Generates a tag given a nofeeswap liquidity position.
  /// @param poolId The pool identifier hosting this liquidity position.
  /// @param qMin Equal to '(2 ** 59) * log(pMin)' where 'pMin' is the left
  /// position boundary.
  /// @param qMax Equal to '(2 ** 59) * log(pMax)' where 'pMax' is the right
  /// position boundary.
  function tag(
    uint256 poolId,
    X59 qMin,
    X59 qMax
  ) internal pure returns (
    Tag positionTag
  ) {
    assembly {
      // Cache the free memory pointer so that the third memory slot can be
      // used for hashing.
      let freeMemoryPointer := mload(0x40)
      mstore(64, qMax)
      mstore(32, qMin)
      mstore(0, poolId)
      positionTag := keccak256(0, 96)
      // The 'freeMemoryPointer' is restored.
      mstore(0x40, freeMemoryPointer)
    }
  }
}

contracts/utilities/X216.sol.content:
// Copyright 2025, NoFeeSwap LLC - All rights reserved.
pragma solidity ^0.8.28;

import {FullMathLibrary} from "./FullMath.sol";

// Type 'X216' is dedicated to integrals and sqrt of price values.
type X216 is int256;

using X216Library for X216 global;

X216 constant oneX216 = X216.wrap(1 << 216);
X216 constant zeroX216 = X216.wrap(0);
X216 constant epsilonX216 = X216.wrap(1);
// (2 ** 216) * exp(-8)
X216 constant expInverse8X216 = X216.wrap(
  0x00000000000015FC21041027ACBBFCD46780FEE71EAD23FBCB7F4A81E58767EF
);

using {equals as ==, notEquals as !=} for X216 global;
using {lessThan as <, greaterThan as >} for X216 global;
using {
  lessThanOrEqualTo as <=,
  greaterThanOrEqualTo as >=
} for X216 global;
using {add as +, sub as -} for X216 global;
using {mul as *, cheapMul as &} for X216 global;
using {mulDivByExpInv8 as %, mulDivByExpInv16 as ^} for X216 global;

function equals(
  X216 value0,
  X216 value1
) pure returns (
  bool result
) {
  assembly {
    result := eq(value0, value1)
  }
}

function notEquals(
  X216 value0,
  X216 value1
) pure returns (
  bool result
) {
  return !(value0 == value1);
}

function lessThan(
  X216 value0,
  X216 value1
) pure returns (
  bool result
) {
  assembly {
    result := slt(value0, value1)
  }
}

function greaterThan(
  X216 value0,
  X216 value1
) pure returns (
  bool result
) {
  assembly {
    result := sgt(value0, value1)
  }
}

function lessThanOrEqualTo(
  X216 value0,
  X216 value1
) pure returns (
  bool result
) {
  return !(value0 > value1);
}

function greaterThanOrEqualTo(
  X216 value0,
  X216 value1
) pure returns (
  bool result
) {
  return !(value0 < value1);
}

// Overflow/underflow should be avoided externally.
function add(
  X216 value0,
  X216 value1
) pure returns (
  X216 result
) {
  assembly {
    result := add(value0, value1)
  }
}

// Overflow/underflow should be avoided externally.
function sub(
  X216 value0,
  X216 value1
) pure returns (
  X216 result
) {
  assembly {
    result := sub(value0, value1)
  }
}

// Calculates '(value0 * value1) / (2 ** 216)'.
// Overflow/underflow should be avoided externally.
// Both values should be greater than '- 2 ** 255'.
function mul(
  X216 value0,
  X216 value1
) pure returns (
  X216 result
) {
  // Let 's := value0 * value1 - (2 ** 256 - 1) * p'
  // Let 'r := value0 * value1 - (2 ** 216) * q'
  // Then 's - r == (2 ** 216) * q' [modulo '2 ** 256 - 1']
  // Then 'q == (2 ** 40) * (s - r)' [modulo '2 ** 256 - 1']
  assembly {
    result := mulmod(
      addmod(
        // We account for the additional term '2 ** 256' in two's complement
        // representation by subtracting 'slt(value, 0)'. Because if a two's
        // complement representation 'value' correspond to a negative number,
        // we have:
        //
        // 'value - 2 ** 256 == value - 1' [modulo 2 ** 256 - 1]
        //
        // Both subtractions are safe due to the input requirement.
        mulmod(
          sub(value0, slt(value0, 0)),
          sub(value1, slt(value1, 0)),
          not(0)
        ), // s
        // Here, we do not need to account for the additional term '2 ** 256'
        // in two's complement representation because if a two's complement
        // representation 'value' is negative, we have:
        //
        // 'value - 2 ** 256 == value' [modulo 2 ** 216]
        //
        // The subtraction is safe because '2 ** 216 < 2 ** 256 - 1'.
        sub(not(0), mulmod(value0, value1, shl(216, 1))), // 0 - r
        not(0)
      ),
      shl(40, 1),
      not(0)
    )
  }
}

// Calculates '(value0 * value1) / (2 ** 216)'.
// 'value0' and 'value1' should be non-negative and less than 'oneX216'.
function cheapMul(
  X216 value0,
  X216 value1
) pure returns (
  X216 result
) {
  // Let 's := value0 * value1 - (2 ** 216 - 1) * p'
  // Let 'r := value0 * value1 - (2 ** 216) * q'
  // Then 's - r == q' [modulo '2 ** 216 - 1']
  // Because of the input requirements, 'q' does not exceed '2 ** 216 - 1'
  // which concludes that: 's - r == q'.
  assembly {
    result := addmod(
      mulmod(value0, value1, sub(shl(216, 1), 1)), // s
      // The subtraction is safe because the output of 'mulmod' does not exceed
      // '2 ** 216 - 1'.
      sub(sub(shl(216, 1), 1), mulmod(value0, value1, shl(216, 1))), // 0 - r
      sub(shl(216, 1), 1)
    )
  }
}

// Calculates '(value0 * value1) / ((2 ** 216) * exp(-8))'.
//
// The following approximation is used: '(2 ** 216) * exp(-8) ~= b / a' where
// 'a = 0xF8F6376C44' and 
// 'b = 0x1561650620DABB6A84B684E2A7E5A47CAA0A0905210083F0E3B551AABF84E9'
//
// Overflow should be avoided externally.
// Both values should be non-negative.
// 'value0' should be less than 'oneX216'.
function mulDivByExpInv8(
  X216 value0,
  X216 value1
) pure returns (
  X216 result
) {
  // Let 's := value0 * value1 * a - (2 ** 256) * p'
  // Let 'r := value0 * value1 * a - b * q'
  // Then 's - r == b * q' [modulo '2 ** 256']
  assembly {
    // Multiplication is safe because of the input requirement:
    // '0 <= value0 < oneX216'.
    result := mul(value0, 0xF8F6376C44)
    result := mul(
      // s - r
      sub(
        // s
        mul(result, value1),
        // r
        mulmod(
          result,
          value1,
          0x1561650620DABB6A84B684E2A7E5A47CAA0A0905210083F0E3B551AABF84E9 // b
        )
      ),
      // modular inverse of 'b' modulo '2 ** 256'
      0x28256938C4923FF15AB260970AA81F81C15E6F5EF3AF38DC210569E77DB19359
    )
  }
}

// Calculates '(value0 * value1) / ((2 ** 216) * exp(-16))'.
//
// The following approximation is used: '(2 ** 216) * exp(-16) ~= b / a' where
// 'a = 0x27D117D7B * 0x2EC3A856' and 
// 'b = 0xDBB82F7041B890FE67970A62A3568CC34DF9DCB17CC3A2A6A027850E7E3724F9'
//
// Overflow should be avoided externally.
// Both values should be non-negative.
// 'value0' and 'value1' should be less than 'oneX216'.
function mulDivByExpInv16(
  X216 value0,
  X216 value1
) pure returns (
  X216 result
) {
  // Let 's := value0 * value1 * a - (2 ** 256) * p'
  // Let 'r := value0 * value1 * a - b * q'
  // Then 's - r == b * q' [modulo '2 ** 256']
  assembly {
    // Both of the following multiplications are safe because of the input
    // requirements:
    // '0 <= value0 < oneX216'.
    // '0 <= value1 < oneX216'.
    value0 := mul(value0, 0x27D117D7B)
    value1 := mul(value1, 0x2EC3A856)
    result := mul(
      // s - r
      sub(
        // s
        mul(value0, value1),
        // r
        mulmod(
          value0,
          value1,
          // b
          0xDBB82F7041B890FE67970A62A3568CC34DF9DCB17CC3A2A6A027850E7E3724F9
        )
      ),
      // modular inverse of 'b' modulo '2 ** 256'
      0x7F6AF8233BADA11DD406B4458454ED9904D7AF796BE7AA4885B23E25B6985D49
    )
  }
}

function min(
  X216 value0,
  X216 value1
) pure returns (
  X216 result
) {
  return (value0 < value1) ? value0 : value1;
}

function max(
  X216 value0,
  X216 value1
) pure returns (
  X216 result
) {
  return (value0 < value1) ? value1 : value0;
}

/// @notice Returns the minimum of two unsigned fractions. '0 / 0' is 
/// interpreted as infinity. 'which == false' and 'which == true' indicate
/// '(numerator0, denominator0)' and '(numerator1, denominator1)',
/// respectively.
/// All four values should be non-negative.
/// At least one 'denominator' should be non-zero.
function minFractions(
  X216 numerator0,
  X216 denominator0,
  X216 numerator1,
  X216 denominator1
) pure returns (
  X216 numerator,
  X216 denominator,
  bool which
) {
  if (numerator0 == zeroX216) {
    if (denominator0 == zeroX216) {
      return (numerator1, denominator1, true);
    }
  }
  // Castings are safe because all four values are non-negative.
  (uint256 lsb0, uint256 msb0) = FullMathLibrary.mul512(
    uint256(X216.unwrap(numerator0)),
    uint256(X216.unwrap(denominator1))
  );
  (uint256 lsb1, uint256 msb1) = FullMathLibrary.mul512(
    uint256(X216.unwrap(numerator1)),
    uint256(X216.unwrap(denominator0))
  );
  (numerator, denominator, which) = 
    ((msb1 > msb0) || ((msb1 == msb0) && (lsb1 >= lsb0))) ? 
    (numerator0, denominator0, false) : 
    (numerator1, denominator1, true);
}

library X216Library {
  /// @notice Calculates 'value * exp(1 / (2 ** 60))'.
  /// Overflow should be avoided externally.
  /// 'value' should be non-negative.
  function multiplyByExpEpsilon(
    X216 value
  ) internal pure returns (
    X216 result
  ) {
    // Let 'a := floor((2 ** 256) * exp(-1 / (2 ** 60)))'
    // Let 'r := (2 ** 256) * value - a * q'
    // Let 'b := modularInverse(- a, 2 ** 256)'
    // Then 'q == b * r' [modulo '2 ** 256']
    assembly {
      result := mul(
        // r
        mulmod(
          value,
          // We are subtracting by 'a' because '2 ** 256' does not fit, which
          // is okay because the multiplication is done modulo 'a'.
          // 2 ** 256 - a
          0xFFFFFFFFFFFFFFF8000000000000002AAAAAAAAAAAAAAA001,
          // a
          0xFFFFFFFFFFFFFFF0000000000000007FFFFFFFFFFFFFFD555555555555555FFF
        ),
        // b
        0xAA3ED2381A8B1241D16168FD77EF989ED2B13BE12B716AA23F35ED0E39556001
      )
    }
  }

  /// @notice Calculates 'value / exp(1 / (2 ** 60))'.
  /// 'value' should be non-negative.
  function divideByExpEpsilon(
    X216 value
  ) internal pure returns (
    X216 result
  ) {
    assembly {
      // Let 'a := floor((2 ** 256 - 1) * exp(-1 / (2 ** 60)))'.
      // Let 's := value * a - q * not(0)'.
      // Let 'r := value * a'.
      // Then 's - r == - q * not(0) == q'.
      result := sub(
        // s
        mulmod(
          value,
          // a
          0xFFFFFFFFFFFFFFF0000000000000007FFFFFFFFFFFFFFD555555555555555FFE,
          not(0)
        ),
        // r
        mul(
          value,
          // a
          0xFFFFFFFFFFFFFFF0000000000000007FFFFFFFFFFFFFFD555555555555555FFE
        )
      )
    }
  }

  /// @notice Calculates '(value * numerator) / denominator'
  /// Overflow and division by zero should be avoided externally.
  /// All input values should be non-negative.
  function mulDiv(
    X216 value,
    X216 numerator,
    X216 denominator
  ) internal pure returns (
    X216 result
  ) {
    result = X216.wrap(
      // Casting is safe because overflow is handled externally.
      int256(
        // All three castings are safe due to the input requirements.
        FullMathLibrary.mulDiv(
          uint256(X216.unwrap(value)),
          uint256(X216.unwrap(numerator)),
          uint256(X216.unwrap(denominator))
        )
      )
    );
  }

  /// @notice Calculates '(value * numerator) / denominator' when 
  /// 'value * numerator < denominator * (denominator - 1)'.
  /// value should be non-negative
  function cheapMulDiv(
    X216 value,
    uint256 numerator,
    uint256 denominator
  ) internal pure returns (
    X216 result
  ) {
    result = X216.wrap(
      // Casting is safe because overflow is handled externally.
      int256(
        // The requirement of 'cheapMulDiv' is met because of the above input
        // requirement.
        FullMathLibrary.cheapMulDiv(
          // Casting is safe due to the input requirement in 'value'.
          uint256(X216.unwrap(value)),
          numerator,
          denominator
        )
      )
    );
  }
}

